188→
189→    const getComputedStarPosition = useCallback((post) => {
190→        if (!post) return null;
191→
192→        const uid = post.users?.id ?? post.user_id;
193→        const hashGal = userHomeCoords(uid);
194→        const animGal = galaxyPositions.get(uid);
195→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
196→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
197→        const pull = starPullOffsets.get(post.id);
