481→    const handleWormholeTravel = useCallback(() => {
482→        if (!selectedPost || isFlying.current) return;
483→        const match = getWormholeForPost(selectedPost.id);
484→        if (!match) return;
485→        const { wormhole, side } = match;
486→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
487→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
488→        setSelectedPost(null);
489→        setIsWarping(true);
490→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
491→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
492→
493→    // One-time auto focus after first payload is loaded.
494→    useEffect(() => {
495→        if (!userId) return;
496→        if (isInitialLoading) return;
497→        if (hasAutoFocusedOwnGalaxyRef.current) return;
498→
499→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
500→        const target = ownGalaxy
501→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
502→            : (centroidTargets.get(userId) || ownGalaxyTarget);
503→
504→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
505→        if (!target) return;
506→
507→        hasAutoFocusedOwnGalaxyRef.current = true;
508→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
509→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
510→
511→    const settledPayload = useMemo(() => {
512→        if (!isSettled || activePosts.length === 0) return [];
513→
514→        const payload = [];
515→        for (const post of activePosts) {
516→            if (!post?.id) continue;
517→            const pos = getComputedStarPosition(post);
518→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
519→
520→            payload.push({
521→                post_id: post.id,
522→                settled_x: Math.round(pos.x * 100) / 100,
523→                settled_y: Math.round(pos.y * 100) / 100,
524→            });
525→        }
526→
527→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
528→        return payload;
529→    }, [activePosts, getComputedStarPosition, isSettled]);
530→
531→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
532→    useEffect(() => {
533→        if (!ENABLE_SETTLED_RPC_SAVE) return;
534→        if (!isSettled || settledPayload.length === 0) return;
535→
536→        const signature = JSON.stringify(settledPayload);
537→        if (signature === lastSettledPayloadRef.current) return;
538→
539→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
540→        settleDebounceRef.current = setTimeout(async () => {
541→            lastSettledPayloadRef.current = signature;
542→            try {
543→                const { error } = await supabase.rpc('save_universe_settled_positions', {
544→                    positions_payload: settledPayload,
545→                });
546→                if (error) {
547→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
548→                }
549→            } catch (err) {
550→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
551→            }
552→        }, 1200);
553→
554→        return () => {
555→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
556→        };
557→    }, [isSettled, settledPayload]);
558→
559→    // ESC key to cancel link mode
560→    useEffect(() => {
561→        if (!isLinkMode) return;
562→        const handleKeyDown = (e) => {
563→            if (e.key === 'Escape') cancelLinkMode();
564→        };
565→        window.addEventListener('keydown', handleKeyDown);
566→        return () => window.removeEventListener('keydown', handleKeyDown);
567→    }, [isLinkMode, cancelLinkMode]);
568→
569→    useEffect(() => {
570→        return () => {
571→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
572→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
573→        };
574→    }, []);
575→
576→    return (
577→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
578→            <button className={styles.backButton} onClick={() => navigate('/home')}>
579→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
580→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
581→                </svg>
582→                Back
583→            </button>
584→
585→            {userId && (
586→                <button
587→                    className={`${styles.linkModeButton} ${isLinkMode ? styles.linkModeActive : ''}`}
588→                    onClick={toggleLinkMode}
589→                    disabled={isSubmitting}
590→                >
591→                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
592→                        <path d="M3.9 12c0-1.71 1.39-3.1 3.1-3.1h4V7H7c-2.76 0-5 2.24-5 5s2.24 5 5 5h4v-1.9H7c-1.71 0-3.1-1.39-3.1-3.1zM8 13h8v-2H8v2zm9-6h-4v1.9h4c1.71 0 3.1 1.39 3.1 3.1s-1.39 3.1-3.1 3.1h-4V17h4c2.76 0 5-2.24 5-5s-2.24-5-5-5z"/>
593→                    </svg>
594→                    {isLinkMode
595→                        ? (firstStar ? 'Select second star...' : 'Select your star...')
596→                        : 'Link Stars'}
597→                </button>
598→            )}
599→
600→            {isLinkMode && (
601→                <div className={styles.linkModeIndicator}>
602→                    <span>
603→                        {linkModeError
604→                            ? linkModeError
605→                            : firstStar
606→                                ? `Selected "${firstStar.title}" — now click another user's star`
607→                                : 'Click one of your stars to begin'}
608→                    </span>
609→                    <button className={styles.linkModeCancel} onClick={cancelLinkMode}>Cancel</button>
610→                </div>
611→            )}
612→
613→            <div className={styles.distanceTracker}>
614→                {(() => {
615→                    const dx = centerWorld.x - homePosition.x;
616→                    const dy = centerWorld.y - homePosition.y;
617→                    const dist = Math.round(Math.sqrt(dx * dx + dy * dy));
618→                    return dist < 50
619→                        ? 'Home'
620→                        : `${dist.toLocaleString()} Lightyears from Home`;
621→                })()}
622→            </div>
623→
624→            {isInitialLoading && (
625→                <div className={styles.loadingOverlay}>
626→                    <div className={styles.loadingCard}>
627→                        <div className={styles.loadingSpinner} />
628→                        <div className={styles.loadingText}>Loading universe...</div>
629→                    </div>
630→                </div>
631→            )}
632→
633→            <Stage
634→                ref={stageRef}
635→                width={stageSize.width}
636→                height={stageSize.height}
637→                {...stageEvents}
638→            >
639→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
640→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
641→                <NebulaLayer
642→                    layerProps={getLayerProps(0.85)}
643→                    galaxies={galaxies}
644→                    centroids={centroids}
645→                />
646→                {enrichedWormholes.length > 0 && (
647→                    <WormholeLayer
648→                        layerProps={getLayerProps(1.0)}
649→                        wormholes={enrichedWormholes}
650→                        zoom={zoom}
651→                    />
652→                )}
653→                {constellations.length > 0 && (
654→                    <ConstellationLayer
655→                        layerProps={getLayerProps(1.0)}
656→                        constellations={constellations}
657→                        computedStarPositions={finalStarPositions}
658→                        zoom={zoom}
659→                        chainColors={chainColors}
660→                        userId={userId}
661→                    />
662→                )}
663→                <InteractiveLayer
664→                    layerProps={getLayerProps(1.0)}
665→                    posts={postArray}
666→                    galaxies={galaxies}
667→                    zoom={zoom}
668→                    showTitles={showTitles}
669→                    pulsingId={pulsingId}
670→                    onStarClick={handleStarClick}
671→                    onGalaxyClick={handleGalaxyClick}
672→                    galaxyPositions={galaxyPositions}
673→                    starPullOffsets={starPullOffsets}
674→                    similarPairs={similarPairs}
675→                    galaxyEdges={effectiveGalaxyEdges}
676→                    activePostIds={activePostIds}
677→                    useEmbeddingBridges={hasEmbeddingGravity}
678→                    camera={camera}
679→                    stageSize={stageSize}
680→                    computedStarPositions={finalStarPositions}
681→                />
682→            </Stage>
683→
684→            {isWarping && <div className={styles.warpOverlay} />}
685→
686→            <UniverseMinimap
687→                galaxies={galaxies}
688→                camera={camera}
689→                zoom={zoom}
690→                stageSize={stageSize}
691→                onNavigate={handleMinimapNavigate}
692→                constellations={acceptedConstellations}
693→                computedStarPositions={finalStarPositions}
694→            />
695→
696→            {selectedGalaxy && galaxyProfile && (
697→                <div className={styles.galaxyPreviewPanel}>
698→                    <button
699→                        className={styles.galaxyPreviewClose}
700→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
701→                    >
702→                        &times;
703→                    </button>
704→                    <div
705→                        className={styles.galaxyPreviewBg}
706→                        style={galaxyProfile.background || {}}
707→                    />
708→                    <div className={styles.galaxyPreviewContent}>
709→                        <img
710→                            className={styles.galaxyPreviewAvatar}
711→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
712→                            alt=""
713→                        />
714→                        <div className={styles.galaxyPreviewHeading}>
715→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
716→                        </div>
717→                        {galaxyProfile.bio && (
718→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
719→                        )}
720→                        <button
721→                            className={styles.galaxyPreviewVisitBtn}
722→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
723→                        >
724→                            Visit Profile
725→                        </button>
726→                    </div>
727→                </div>
728→            )}
729→
730→            {selectedPost && (
731→                <div className={styles.previewPanel}>
732→                    <button
733→                        className={styles.previewClose}
734→                        onClick={() => setSelectedPost(null)}
735→                    >
736→                        &times;
737→                    </button>
738→                    <div className={styles.previewAuthor}>
739→                        <img
740→                            className={styles.previewAvatar}
741→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
742→                            alt=""
743→                        />
744→                        <span className={styles.previewAuthorName}>
745→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
746→                        </span>
747→                    </div>
748→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
749→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
750→                    <div className={styles.previewLikes}>
751→                        {(() => {
752→                            const count = selectedPost.like_count != null
753→                                ? selectedPost.like_count
754→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
755→                                    ? selectedPost.likes[0].count : 0);
756→                            return `${count} like${count !== 1 ? 's' : ''}`;
757→                        })()}
758→                    </div>
759→                    <div className={styles.previewActions}>
760→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
761→                            Read
762→                        </button>
763→                        {getWormholeForPost(selectedPost.id) && (
764→                            <div className={styles.wormholeBtnWrap}>
765→                                <button className={styles.wormholeBtn} onClick={handleWormholeTravel}>
766→                                    Wormhole to "{getWormholeForPost(selectedPost.id).targetTitle}"
767→                                </button>
768→                                <div className={styles.wormholeTooltip}>
769→                                    This post is semantically linked to a distant post. Click to warp there instantly.
770→                                </div>
771→                            </div>
772→                        )}
773→                    </div>
774→                </div>
775→            )}
776→        </div>
777→    );
778→};
